Concrete C++ implementation of Kadane (non-empty array, handles all-negative correctly, uses long long for overflow safety):

#include <vector>
#include <algorithm>

long long max_subarray_sum(const std::vector<long long>& a) {
    // Precondition: a is non-empty.
    long long current = a[0];
    long long best    = a[0];
    for (size_t i = 1; i < a.size(); ++i) {
        current = std::max(a[i], current + a[i]);
        best    = std::max(best, current);
    }
    return best;
}
